diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..fe3bd6803 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -578,7 +578,6 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 	fz_catch(ctx)
 		fz_rethrow(ctx);

-	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
 	fontdesc->is_embedded = 1;
 }

diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..4a6481066 100644
