+++ b/source/pdf/pdf-font.c
@@ -555,6 +555,7 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 	size_t size;

 	buf = pdf_load_stream(ctx, stmref);
+	size = fz_buffer_storage(ctx, buf, &data); // Capture size early

 	fz_try(ctx)
 	{
@@ -578,7 +579,7 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 	fz_catch(ctx)
 		fz_rethrow(ctx);

-	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
+	fontdesc->size += size;
 	fontdesc->is_embedded = 1;
 }

