diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..a678bbf3a 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -574,11 +574,15 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 		fontdesc->font = fz_new_font_from_buffer(ctx, fontname, buf, 0, 1);
 	}
 	fz_always(ctx)
-		fz_drop_buffer(ctx, buf);
+	{
+		if (buf) {
+			fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
+			fz_drop_buffer(ctx, buf);
+			buf = NULL;
+		}
+	}
 	fz_catch(ctx)
 		fz_rethrow(ctx);
-
-	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
 	fontdesc->is_embedded = 1;
 }

diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..6aa74357c 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -572,13 +572,13 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 		}

 		fontdesc->font = fz_new_font_from_buffer(ctx, fontname, buf, 0, 1);
+		fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
 	}
 	fz_always(ctx)
 		fz_drop_buffer(ctx, buf);
 	fz_catch(ctx)
 		fz_rethrow(ctx);

-	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
 	fontdesc->is_embedded = 1;
 }

diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..a9129ec13 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -565,8 +565,9 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 				fz_buffer *cff = pdf_extract_cff_subtable(ctx, data, size);
 				if (cff)
 				{
-					fz_drop_buffer(ctx, buf);
+					fz_buffer *old_buf = buf;
 					buf = cff;
+					fz_drop_buffer(ctx, old_buf);
 				}
 			}
 		}

diff --git a/source/pdf/pdf-font.c b/source/pdf/pdf-font.c
index e071e8bd4..a97f31665 100644
--- a/source/pdf/pdf-font.c
+++ b/source/pdf/pdf-font.c
@@ -550,7 +550,7 @@ pdf_extract_cff_subtable(fz_context *ctx, unsigned char *data, size_t size)
 static void
 pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontdesc, const char *fontname, pdf_obj *stmref)
 {
-	fz_buffer *buf;
+	fz_buffer *buf = NULL;
 	unsigned char *data;
 	size_t size;

@@ -578,7 +578,8 @@ pdf_load_embedded_font(fz_context *ctx, pdf_document *doc, pdf_font_desc *fontde
 	fz_catch(ctx)
 		fz_rethrow(ctx);

-	fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
+	if (buf)
+		fontdesc->size += fz_buffer_storage(ctx, buf, NULL);
 	fontdesc->is_embedded = 1;
 }

